1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote - base premiums", () => {
6	    it("returns 5 G for an empty item list (processing fee only)", () => {
7	      const scenario = {
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote" as const, items: [] }],
10	      };
11	      const result = processScenario(scenario);
12	      expect(result.results[0]).toEqual({ premium: 5 });
13	    });
14	    it.todo("returns base premium + fee for a single sword (100 + 5 = 105 G)");
15	    it.todo("returns base premium + fee for a single amulet (60 + 5 = 65 G)");
16	    it.todo("returns base premium + fee for a single staff (80 + 5 = 85 G)");
17	    it.todo("returns base premium + fee for a single potion (40 + 5 = 45 G)");
18	    it.todo("returns 25 G base premium per component (e.g. 1 rune = 30 G with fee)");
19	    it.todo("sums base premiums for multiple items (sword + amulet = 160 + 5 = 165 G)");
20	  });
21	
22	  describe("Quote - component block pricing", () => {
23	    it.todo("charges 50 G base for 2 alike components (no block)");
24	    it.todo("charges 60 G base for exactly 3 alike components (block applies)");
25	    it.todo("charges 100 G base for 4 alike components (no block)");
26	    it.todo("charges 75 G base for 2 runes + 1 moonstone (different types, no block)");
27	    it.todo("charges 120 G base for 3 runes + 3 moonstones (two separate blocks)");
28	  });
29	
30	  describe("Quote - item-specific modifiers", () => {
31	    it.todo("adds 50% surcharge to a cursed item's base premium");
32	    it.todo("adds 30% surcharge for enchantment level >= 5");
33	    it.todo("applies both cursed and high-enchantment surcharges to the same item");
34	    it.todo("does not add high-enchantment surcharge for enchantment level 4");
35	    it.todo("cursed surcharge applies only to the cursed item in a multi-item policy");
36	  });
37	
38	  describe("Quote - policy-wide modifiers", () => {
39	    it.todo("applies 10% first insurance surcharge to policy base premium");
40	    it.todo("applies 20% loyalty discount for customer with >= 2 years");
41	    it.todo("applies 15% follow-up discount on second quote");
42	    it.todo("applies both loyalty and follow-up discounts together");
43	  });
44	
45	  describe("Quote - integration", () => {
46	    it.todo("newcomer with cursed sword: 165 G");
47	    it.todo("long-standing customer second contract with cursed enchanted sword: 160 G");
48	    it.todo("rounds premium up to whole G in MHPCO's favor");
49	  });
50	
51	  describe("Claim - basic payout", () => {
52	    it.todo("applies 100 G deductible to damage on a regular item");
53	    it.todo("fully reimburses dragon-material item minus deductible");
54	    it.todo("reimburses 50% for enchantment >= 8, then applies deductible");
55	    it.todo("applies 50% rule when item is both dragon-material and enchantment >= 8");
56	    it.todo("fully reimburses dragon-material item with enchantment < 8 minus deductible");
57	  });
58	
59	  describe("Claim - deductible per item", () => {
60	    it.todo("applies deductible separately to each damaged item in an event");
61	    it.todo("component damage uses full reimbursement minus deductible");
62	  });
63	
64	  describe("Claim - cap", () => {
65	    it.todo("caps total payout at 2x insurance sum");
66	    it.todo("tracks remaining cap across successive claims");
67	    it.todo("insurance sum is based on item values, not premiums");
68	    it.todo("component block discount does not affect insurance sum");
69	  });
70	
71	  describe("Claim - rounding", () => {
72	    it.todo("rounds payout down to whole G in MHPCO's favor");
73	  });
74	
75	  describe("Error handling", () => {
76	    it.todo("rejects unknown item type in quote");
77	    it.todo("rejects claim referencing item not in policy");
78	    it.todo("rejects negative damage amount");
79	    it.todo("rejects more damages of a type than policy covers");
80	  });
81	
82	  describe("CLI integration", () => {
83	    it.todo("processes a scenario with quote and claim steps via CLI");
84	  });
85	});
86

